module RefModule (
    input clk,
    input reset,
    input [15:0] data_in,
    output [15:0] data_out
);

    reg [15:0] obf_pipeline [0:3];  // 4-stage obf_pipeline

    always @(posedge clk) begin
        if (reset) begin
            obf_pipeline[0] <= 16'b0;
            obf_pipeline[1] <= 16'b0;
            obf_pipeline[2] <= 16'b0;
            obf_pipeline[3] <= 16'b0;
        end else begin
            obf_pipeline[0] <= data_in;
            obf_pipeline[1] <= obf_pipeline[0];
            obf_pipeline[2] <= obf_pipeline[1];
            obf_pipeline[3] <= obf_pipeline[2];
        end
    end

    assign data_out = obf_pipeline[3];

endmodule
